import{_ as a}from"./chunks/rescue-shell.DjMq5tQD.js";import{_ as e,o as i,c as s,ae as o}from"./chunks/framework.RRduUuAx.js";const l="/screenshots/external-drive-conf.png",n="/screenshots/rufus-format.png",b=JSON.parse('{"title":"External Installation - Method 1 (using a script)","description":"","frontmatter":{"prev":{"text":"Go back to Installation Methods","link":"/installation"},"next":{"text":"Ending","link":"/ending"}},"headers":[],"relativePath":"ps4/external-installation-scripted.md","filePath":"ps4/external-installation-scripted.md","lastUpdated":null}'),r={name:"ps4/external-installation-scripted.md"};function d(h,t,c,u,p,m){return i(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="external-installation-method-1-using-a-script" tabindex="-1">External Installation - Method 1 (using a script) <a class="header-anchor" href="#external-installation-method-1-using-a-script" aria-label="Permalink to &quot;External Installation - Method 1 (using a script)&quot;">​</a></h1><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Remember we&#39;ll format the external drive! Back up any existing data you care about.</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If you have issues or just want to do manual partitioning (which often works better) try the <a href="/external-installation-manual.html">alternative installation here</a>.</p></div><h2 id="installation-scripts" tabindex="-1">Installation scripts <a class="header-anchor" href="#installation-scripts" aria-label="Permalink to &quot;Installation scripts&quot;">​</a></h2><p>Put the kernel (bzImage, and the bootargs if you need it), initramfs (initramfs.cpio.gz), and your distro <code>psxitarch.tar.xz/gz</code> on the root of a FAT32 formatted drive, like so:</p><img src="'+l+'" width="75%"><h3 id="manual-format-for-big-drives" tabindex="-1">Manual format for big drives <a class="header-anchor" href="#manual-format-for-big-drives" aria-label="Permalink to &quot;Manual format for big drives&quot;">​</a></h3><p>If the drive is larger than 32GB, Windows will dastardly act like it can&#39;t format it in FAT32, but only in NTFS or ExFAT, which is just wrong, as FAT32 supports up to 2TB drives. To fix it, go ahead and download the mythical <a href="https://rufus.ie" target="_blank" rel="noreferrer">Rufus</a> program.</p><ul><li>Select &quot;List USB Hard Drives&quot;</li><li>Select &quot;Non bootable&quot; as a type of format</li><li>Select &quot;MBR&quot; as partition scheme</li><li>Select &quot;FAT32&quot; as filesystem</li></ul><p>Click start and wait. Once done, place the files on the drive. Plug your drive on the PS4 and continue.</p><img src="'+n+'" width="50%"><h2 id="installation-commands" tabindex="-1">Installation commands <a class="header-anchor" href="#installation-commands" aria-label="Permalink to &quot;Installation commands&quot;">​</a></h2><p>Now that the storage is covered, here comes the moment of truth. You&#39;ll be sent to the Rescue Shell, which will look like this:</p><img src="'+a+'" width="80%"><ul><li>Type <code>install-psxitarch.sh</code><ul><li>If it fails, go to the <a href="/issues.html#installation-issues">Installation Issues</a>, or use the <a href="/external-installation-manual.html">alternative method</a>.</li></ul></li></ul><p>Hydrate yourself while you wait. It&#39;ll take a while.</p><p>After that is done, it should boot into the desktop. If it doesn&#39;t, run</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resume-boot</span></span></code></pre></div><h2 id="finale" tabindex="-1">Finale <a class="header-anchor" href="#finale" aria-label="Permalink to &quot;Finale&quot;">​</a></h2><p>Go now, conquer the finale. Also, read the post-credit stuff.</p>',20)])])}const k=e(r,[["render",d]]);export{b as __pageData,k as default};
